+        let a_freq = 3.0_f64;
+        let b_freq = 2.0_f64;
+        let phase = self.tick_count as f64 * 0.05;
+        let cx = pw as f64 / 2.0;
+        let cy = ph as f64 / 2.0;
+        let rx = (pw as f64 / 2.0) - 2.0;
+        let ry = (ph as f64 / 2.0) - 2.0;
